                }


                /* stroke */
                .menu-dokumenti.stroke,
                .menu-dokumenti.fill {
                  position: relative;
                }
                .menu-dokumenti.stroke:after,
                .menu-dokumenti.fill:after {
                  position: absolute;
                  bottom: 0;
                  left: 0;
                  right: 0;
                  margin: auto;
                  width: 0%;
                  content: '.';
                  color: transparent;
                  background: #D4145A;
                  height: 1px;
                }

                .menu-dokumenti.stroke:hover:after {
                  width: 100%;
                }

                .menu-dokumenti.fill {
                  transition: all 2s;
